function cloudSidebarHtml(){const connected=cloudConnected(),doc=activeProfileDoc(),profiles=doc?.profiles||[],active=activeProfile(),needsLogin=state.cloud.enabled&&!connected&&!state.cloud.reconnecting,reconnecting=state.cloud.enabled&&!connected&&state.cloud.reconnecting,setup=!supabaseReady();return `<div class="cloud-panel ${needsLogin||setup?'cloud-needs-login':''} ${reconnecting?'cloud-reconnecting':''}"><p class="side-title">${connected?'Cloud save':'Profiles'}</p><label class="side-field">Profile<select id="cloudProfileSelect">${profiles.map(p=>`<option value="${p.id}" ${p.id===state.cloud.activeProfileId?'selected':''}>${p.name}</option>`).join('')}</select></label><small class="cloud-status">${setup?'Supabase setup needed':connected?state.cloud.status:reconnecting?'Restoring Supabase session…':needsLogin?'SIGNED OUT — changes save locally only':'Local profiles'}${active?` · ${active.name}`:''}</small>${setup?'<div class="cloud-warning">Add data/supabase-config.json to enable account sync.</div>':needsLogin?'<div class="cloud-warning">You are signed out. Local changes will not sync until you sign in.</div>':''}<div class="cloud-actions">${connected?'<button class="btn secondary" id="cloudSyncNow">Sync now</button><button class="btn secondary" id="cloudImportGoogle">Import Google Drive profiles</button>':reconnecting?'<button class="btn secondary" disabled>Restoring…</button>':'<button class="btn secondary cloud-connect" id="cloudConnect">Sign in</button><button class="btn secondary" id="cloudCreateAccount">Create account</button><button class="btn secondary" id="cloudResetPassword">Reset password</button>'}<button class="btn secondary" id="cloudNewProfile">New profile</button><button class="btn secondary" id="cloudRenameProfile">Rename</button><button class="btn danger" id="cloudDeleteProfile">Delete</button>${connected?'<button class="btn ghost" id="cloudSignOut">Sign out</button>':''}</div><div class="side-rule"></div></div>`}
