let lastRoutePath='';
function donatePage(){app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / Donate</div><section class="donate-hero"><div class="donate-hero-copy"><p class="eyebrow">Support the archives</p><h1>Buy me a coffee</h1><p>Droid Archives is a free community project. If it has helped you plan your base, track your collection, or prepare for rebirths, you can optionally support its continued development.</p><a class="donate-button" href="https://buymeacoffee.com/droidarchives" target="_blank" rel="noopener noreferrer"><span aria-hidden="true">☕</span> Support Droid Archives</a></div><div class="donate-coffee" aria-hidden="true"><span>☕</span></div></section><section class="donate-content"><div class="donate-message"><p class="eyebrow">Thank you</p><h2>Your support helps keep this project going</h2><p>Donations help with the time and costs involved in maintaining droid data, images, calculators, profiles, and new features for the community.</p><div class="donate-disclaimer"><strong>Support only — no rewards or benefits</strong><p>Donating is completely voluntary. You will not receive in-game items, site features, account benefits, priority support, or anything else in return. Your donation only supports the continued upkeep and development of Droid Archives.</p></div><p class="donate-free"><strong>Droid Archives remains free for everyone.</strong></p></div><a class="donate-qr-card" href="https://buymeacoffee.com/droidarchives" target="_blank" rel="noopener noreferrer" aria-label="Open the Droid Archives Buy Me a Coffee page"><span>Scan to support</span><img src="assets/other/bmc_qr.png" alt="QR code for the Droid Archives Buy Me a Coffee page"><small>buymeacoffee.com/droidarchives</small></a></section>`}
function route(){const path=location.hash.slice(1).split('?')[0]||'/',routeChanged=path!==lastRoutePath;lastRoutePath=path;if(path==='/todo'||path==='/donate')app.querySelector('.archive-timers')?.remove();document.querySelector('.sidebar').classList.remove('mobile-open');renderBaseSidebar(()=>route());renderCloudHeader();if(path==='/')home();else if(path==='/droids')droidsPage();else if(path==='/droidex')droidexPage();else if(path==='/nova-shop')novaShopPage();else if(path.startsWith('/nova-shop/'))novaDetailPage(path.split('/')[2]);else if(path==='/galactic-reports'&&GALACTIC_REPORTS_ENABLED)galacticReportsPage();else if(path==='/todo')todoPage();else if(path==='/donate')donatePage();else if(path==='/base')basePageV2();else if(path==='/rebirth')rebirthPage();else if(path==='/optimise')optimisePage();else if(path==='/lucky-droid')luckyDroidPage();else if(path.startsWith('/droid/'))detailPage(path.split('/')[2]);else notFound();if(routeChanged){try{app.focus({preventScroll:true})}catch{app.focus()}scrollTo(0,0)}setTimeout(showPatchNotesOnce,80)}
function applyTheme(){document.documentElement.dataset.theme=state.theme;document.querySelector('#themeButton').textContent=state.theme==='dark'?'☀':'☾';document.querySelector('#themeButton').title=`Switch to ${state.theme==='dark'?'light':'dark'} mode`}
applyTheme();renderCloudHeader();document.querySelector('#themeButton').onclick=()=>{state.theme=state.theme==='dark'?'light':'dark';save();applyTheme();renderCloudHeader()};document.querySelector('#menuButton').onclick=()=>document.querySelector('.sidebar').classList.toggle('mobile-open');document.addEventListener('click',()=>{const dropdown=document.querySelector('#cloudDropdown'),button=document.querySelector('#cloudMenuButton');if(dropdown){dropdown.hidden=true;button?.setAttribute('aria-expanded','false')}});document.querySelector('#globalSearch').addEventListener('keydown',e=>{if(e.key==='Enter'){location.hash='#/droids';setTimeout(()=>{const s=document.querySelector('#droidSearch');if(s){s.value=e.target.value;s.dispatchEvent(new Event('input'))}},20)}});window.addEventListener('hashchange',route);
document.querySelector('#copyDiscord').onclick=async()=>{try{await navigator.clipboard.writeText('.saltea');toast('Discord username copied')}catch{toast('Discord: .saltea')}};
const DATA_VERSION='2026-07-18-rebirth-30-1';
const loadJson=async path=>{const response=await fetch(`${path}${path.includes('?')?'&':'?'}v=${DATA_VERSION}`);if(!response.ok)throw Error(`Unable to load ${path}`);return response.json()};
async function loadEvents(){try{const index=await loadJson('data/events/index.json');if(!Array.isArray(index.events))return[];return Promise.all(index.events.map(file=>loadJson(`data/events/${file}`)))}catch{return[]}}
async function loadPatchNotes(){try{const data=await loadJson(`data/patch-notes.json?${Date.now()}`);return Array.isArray(data.notes)?data.notes:[]}catch{return[]}}
Promise.all(['data/droids.json','data/rebirth-cycles/index.json','data/image-manifest.json','data/nova-shop.json'].map(loadJson)).then(async([d,cycleIndex,i,novaShop])=>{if(!Array.isArray(cycleIndex.cycles)||!cycleIndex.cycles.length)throw Error('No Super Rebirth cycles are configured.');const [cycles,events]=await Promise.all([Promise.all(cycleIndex.cycles.map(file=>loadJson(`data/rebirth-cycles/${file}`))),loadEvents()]);state.droids=d;state.rebirths=Object.fromEntries(cycles.map((cycle,index)=>[index,cycle]));state.images=i;state.novaShop=novaShop;state.events=events;normalizeLoadedDroidNames();if(!Object.hasOwn(state.rebirths,String(state.cycle)))state.cycle=0;route();loadPatchNotes().then(notes=>{state.patchNotes=notes;showPatchNotesOnce()});loadSupabaseConfig().then(()=>initSupabaseSafe()).then(()=>renderCloudHeader())}).catch(e=>{app.innerHTML=`<h1>Archive unavailable</h1><p>${e.message}</p>`});
